import { ImageResponse } from 'next/og';
import { MESSAGES } from '@/config/messages';

/**
 * Static OG card for /pitch.
 *
 * Generated by Next.js at build time (compatible with `output: 'export'`) and
 * emitted as `/pitch/opengraph-image.png`. The metadata in `app/pitch/layout.tsx`
 * picks it up automatically — no manual og:image config needed.
 *
 * Constraints: rendered by Satori, which only supports a CSS subset. Every
 * element with multiple children must declare `display: flex`. Avoid
 * `color-mix()`, `background-clip: text`, and `backdrop-filter`.
 */

export const alt = 'Zap Pilot — Investor Pitch';
export const size = { width: 1200, height: 630 };
export const contentType = 'image/png';

// Required for `output: 'export'` — Next.js needs an explicit signal that
// this OG route is rendered at build time, not on demand.
export const dynamic = 'force-static';
export const revalidate = false;

export default function PitchOpenGraphImage() {
  return new ImageResponse(
    <div
      style={{
        width: '100%',
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'space-between',
        padding: '72px 80px',
        // Satori only accepts gradients in `backgroundImage` — bare colors via
        // `background` shorthand are rejected with "Invalid background image".
        backgroundColor: '#0a0a0a',
        backgroundImage:
          'radial-gradient(ellipse 70% 38% at 78% 12%, rgba(212, 197, 163, 0.18), transparent 68%)',
        color: '#f4f4f5',
      }}
    >
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 18,
        }}
      >
        <div
          style={{
            width: 32,
            height: 32,
            borderRadius: 999,
            backgroundImage:
              'radial-gradient(circle at 30% 30%, #ffffff, #d4c5a3 60%, #6a5e44 100%)',
          }}
        />
        <span
          style={{
            fontSize: 20,
            color: '#a1a1aa',
            letterSpacing: 3,
          }}
        >
          ZAP PILOT · INVESTOR PITCH
        </span>
      </div>

      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          gap: 24,
          maxWidth: 1040,
        }}
      >
        <div
          style={{
            fontSize: 76,
            lineHeight: 1.04,
            fontWeight: 400,
            color: '#f4f4f5',
          }}
        >
          {MESSAGES.hero.title.primary}
        </div>
        <div
          style={{
            fontSize: 28,
            color: '#d4c5a3',
            letterSpacing: 0.3,
          }}
        >
          {MESSAGES.slogans.philosophy}
        </div>
      </div>

      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-end',
          fontSize: 18,
          color: '#a1a1aa',
        }}
      >
        <span>zap-pilot.org/pitch</span>
        <span style={{ letterSpacing: 2 }}>
          SELF-CUSTODY · NON-CUSTODIAL · ON-CHAIN
        </span>
      </div>
    </div>,
    { ...size },
  );
}
